queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?life_insurances a :life_insurances .
    ?life_insurances p:policy_number ?policy_number .
    ?life_insurances p:payout ?payout_f .
    FILTER((STR(?payout_f) = "100000" || STR(?payout_f) = "100000.0"))
    BIND(?policy_number AS ?o0)
  }
  UNION
  {
    ?annuities a :annuities .
    ?annuities p:contract_number ?contract_number .
    ?annuities p:payout ?payout_f .
    FILTER((STR(?payout_f) = "100000" || STR(?payout_f) = "100000.0"))
    BIND(?contract_number AS ?o0)
  }
}

